mapper.select:
select  sum(change_balance) expectedRewardData,DATE_FORMAT(create_time, '%Y-%m-%d') xkey from  t_withdrawal where
status=1  AND   create_time < CURDATE()  AND create_time >= DATE_SUB(CURDATE(), INTERVAL 7 DAY)
group  by  DATE_FORMAT(create_time, '%Y-%m-%d') ;

select  sum(amount) expectedRewardDataV2,DATE_FORMAT(create_time, '%Y-%m-%d') xkey from  xms_reward_record where
create_time  < CURDATE() AND  create_time >= DATE_SUB(CURDATE(), INTERVAL 60 DAY)
group  by  DATE_FORMAT(create_time, '%Y-%m-%d') ;
